snippets.C0621:
// C0621 · FizzBuzz
function Solve(n: Integer): string;
var i: Integer; s: TStringBuilder;
begin
  s := TStringBuilder.Create;
  try
    for i := 1 to n do begin
      if (i mod 15 = 0) then s.Append('FizzBuzz')
      else if (i mod 3 = 0) then s.Append('Fizz')
      else if (i mod 5 = 0) then s.Append('Buzz')
      else s.Append(i.ToString);
      if i < n then s.AppendLine;
    end;
    Result := s.ToString;
  finally
    s.Free;
  end;
end;

